import{_ as e,o as l,c as s,a3 as n}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"190. Annualised Salaries Royal Children S Hospital","description":"","frontmatter":{"title":"190. Annualised Salaries Royal Children S Hospital","eba":"Mental Health Services 2024-2028","topics":["leave","annual-leave","hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/wages/190-annualised-salaries-royal-children-s-hospital.md","filePath":"ebas/mental-health/management-admin/wages/190-annualised-salaries-royal-children-s-hospital.md"}'),i={name:"ebas/mental-health/management-admin/wages/190-annualised-salaries-royal-children-s-hospital.md"};function t(r,a,o,d,h,c){return l(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="_190-annualised-salaries-royal-children-s-hospital" tabindex="-1">190. Annualised Salaries Royal Children S Hospital <a class="header-anchor" href="#_190-annualised-salaries-royal-children-s-hospital" aria-label="Permalink to &quot;190. Annualised Salaries Royal Children S Hospital&quot;">​</a></h1><p>This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>190.1</strong> The annualised salary for Employees classified in Grades 3 to 8 pursuant to Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement shall incorporate all previous award or Agreement payments made in respect of all allowances, including but not limited to shift premiums and penalties, on-call and recall payments, annual leave loading, public holidays, weekends, meal allowances, travelling allowances, higher duties allowances and telephone allowances. The annualised salary also incorporates provision for overtime when Employees are required to work outside of normal work hours.</p><p><strong>190.2</strong> The accrual of annual leave, personal leave, superannuation and WorkCover entitlements are not affected by the Agreement, save where otherwise provided for in this Section 5.</p>',4)])])}const u=e(i,[["render",t]]);export{p as __pageData,u as default};
